import{_ as l,o as e,c as o,ag as i}from"./chunks/framework.CTpQozEL.js";const u=JSON.parse('{"title":"Railway","description":"원클릭 템플릿으로 Railway에 OpenClaw 배포","frontmatter":{"title":"Railway","description":"원클릭 템플릿으로 Railway에 OpenClaw 배포"},"headers":[],"relativePath":"install/railway.md","filePath":"install/railway.md","lastUpdated":null}'),t={name:"install/railway.md"};function r(n,a,c,s,d,h){return e(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="railway" tabindex="-1">Railway <a class="header-anchor" href="#railway" aria-label="Permalink to &quot;Railway&quot;">​</a></h1><p>원클릭 템플릿으로 Railway에 OpenClaw를 배포하고 웹 Control UI를 통해 접근합니다. &quot;서버에 터미널 없음&quot; 경로 중 가장 쉬운 방법입니다 — Railway가 게이트웨이를 대신 실행해 줍니다.</p><h2 id="빠른-체크리스트-신규-사용자" tabindex="-1">빠른 체크리스트 (신규 사용자) <a class="header-anchor" href="#빠른-체크리스트-신규-사용자" aria-label="Permalink to &quot;빠른 체크리스트 (신규 사용자)&quot;">​</a></h2><ol><li>아래 <strong>Deploy on Railway</strong> 를 클릭합니다.</li><li><code>/data</code>에 마운트된 <strong>Volume</strong> 을 추가합니다.</li><li>필수 <strong>Variables</strong> 를 설정합니다 (최소 <code>OPENCLAW_GATEWAY_PORT</code> 와 <code>OPENCLAW_GATEWAY_TOKEN</code>).</li><li><code>8080</code> 포트에서 <strong>HTTP Proxy</strong> 를 활성화합니다.</li><li><code>https://&lt;your-railway-domain&gt;/openclaw</code>를 열고 설정한 공유 시크릿으로 연결합니다. 이 템플릿은 기본적으로 <code>OPENCLAW_GATEWAY_TOKEN</code> 을 사용합니다. 비밀번호 인증으로 교체했다면 해당 비밀번호를 사용합니다.</li></ol><h2 id="원클릭-배포" tabindex="-1">원클릭 배포 <a class="header-anchor" href="#원클릭-배포" aria-label="Permalink to &quot;원클릭 배포&quot;">​</a></h2><a href="https://railway.com/deploy/clawdbot-railway-template" target="_blank" rel="noreferrer"> Deploy on Railway </a><p>배포 후, <strong>Railway → 서비스 → Settings → Domains</strong> 에서 공개 URL을 확인합니다.</p><p>Railway는 다음 중 하나를 제공합니다:</p><ul><li>자동 생성된 도메인 (보통 <code>https://&lt;something&gt;.up.railway.app</code>), 또는</li><li>연결한 사용자 정의 도메인.</li></ul><p>그런 다음 다음 주소를 엽니다:</p><ul><li><code>https://&lt;your-railway-domain&gt;/openclaw</code> — Control UI</li></ul><h2 id="제공되는-것" tabindex="-1">제공되는 것 <a class="header-anchor" href="#제공되는-것" aria-label="Permalink to &quot;제공되는 것&quot;">​</a></h2><ul><li>호스팅된 OpenClaw Gateway + Control UI</li><li>Railway Volume(<code>/data</code>) 을 통한 영구 저장소 — <code>openclaw.json</code>, 에이전트별 <code>auth-profiles.json</code>, 채널/프로바이더 상태, 세션, 워크스페이스가 재배포 후에도 유지됩니다.</li></ul><h2 id="필수-railway-설정" tabindex="-1">필수 Railway 설정 <a class="header-anchor" href="#필수-railway-설정" aria-label="Permalink to &quot;필수 Railway 설정&quot;">​</a></h2><h3 id="public-networking" tabindex="-1">Public Networking <a class="header-anchor" href="#public-networking" aria-label="Permalink to &quot;Public Networking&quot;">​</a></h3><p>서비스에 대해 <strong>HTTP Proxy</strong> 를 활성화합니다.</p><ul><li>Port: <code>8080</code></li></ul><h3 id="volume-필수" tabindex="-1">Volume (필수) <a class="header-anchor" href="#volume-필수" aria-label="Permalink to &quot;Volume (필수)&quot;">​</a></h3><p>다음 위치에 마운트된 볼륨을 연결합니다:</p><ul><li><code>/data</code></li></ul><h3 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h3><p>서비스에 다음 변수를 설정합니다:</p><ul><li><code>OPENCLAW_GATEWAY_PORT=8080</code> (필수 — Public Networking의 포트와 일치해야 함)</li><li><code>OPENCLAW_GATEWAY_TOKEN</code> (필수; 관리자 시크릿으로 취급)</li><li><code>OPENCLAW_STATE_DIR=/data/.openclaw</code> (권장)</li><li><code>OPENCLAW_WORKSPACE_DIR=/data/workspace</code> (권장)</li></ul><h2 id="채널-연결" tabindex="-1">채널 연결 <a class="header-anchor" href="#채널-연결" aria-label="Permalink to &quot;채널 연결&quot;">​</a></h2><p><code>/openclaw</code>의 Control UI를 사용하거나 Railway의 셸을 통해 <code>openclaw onboard</code> 를 실행해 채널 설정 방법을 확인합니다:</p><ul><li><a href="/openclaw-docs-ko/channels/telegram">Telegram</a> (가장 빠름 — 봇 토큰만 있으면 됨)</li><li><a href="/openclaw-docs-ko/channels/discord">Discord</a></li><li><a href="/openclaw-docs-ko/channels/">모든 채널</a></li></ul><h2 id="백업-및-마이그레이션" tabindex="-1">백업 및 마이그레이션 <a class="header-anchor" href="#백업-및-마이그레이션" aria-label="Permalink to &quot;백업 및 마이그레이션&quot;">​</a></h2><p>상태, 구성, 인증 프로필, 워크스페이스를 내보냅니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span></span></code></pre></div><p>이 명령은 OpenClaw 상태와 구성된 워크스페이스를 포함한 이식 가능한 백업 아카이브를 생성합니다. 자세한 내용은 <a href="/openclaw-docs-ko/cli/backup">백업</a> 을 참조하세요.</p><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><ul><li>메시징 채널 설정: <a href="/openclaw-docs-ko/channels/">채널</a></li><li>게이트웨이 구성: <a href="/openclaw-docs-ko/gateway/configuration">게이트웨이 구성</a></li><li>OpenClaw 최신 상태 유지: <a href="/openclaw-docs-ko/install/updating">업데이트</a></li></ul>',32)])])}const w=l(t,[["render",r]]);export{u as __pageData,w as default};
